<?php namespace App\Repositories\Payroll;use App\Repositories\BaseRepository;use App\Models\Payroll\Payroll;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class PayrollRepository extends BaseRepository{    public function __construct(Payroll $model)    {        $this->model = $model;        parent::__construct($model);    }    public function getByEmployee(int $employeeId): Collection    {        return $this->findByField('employee_id', $employeeId);    }    public function getByMonth(int $month, int $year): Collection    {        return $this->query()->whereMonth('payroll_month', $month)->whereYear('payroll_year', $year)->get();    }    public function processPayroll(array $data): Payroll    {        return $this->create($data);    }    public function getByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('payment_date', [$startDate, $endDate])->get();    }    public function getPendingPayrolls(): Collection    {        return $this->query()->where('status', 'pending')->get();    }    public function approvePayroll(int $id, ?string $approvedBy = null): bool    {        $data = ['status' => 'approved', 'approved_at' => now()];        if ($approvedBy) {            $data['approved_by'] = $approvedBy;        }        return $this->update($id, $data);    }    public function disbursePayroll(int $id, string $paymentMode): bool    {        return $this->update($id, [            'status' => 'paid',            'payment_mode' => $paymentMode,            'payment_date' => now(),        ]);    }    public function getPayrollSummary(int $month, int $year): array    {        $payrolls = $this->getByMonth($month, $year);        return [            'total_employees' => $payrolls->count(),            'total_gross_salary' => $payrolls->sum('gross_salary'),            'total_deductions' => $payrolls->sum('total_deductions'),            'total_net_salary' => $payrolls->sum('net_salary'),            'approved' => $payrolls->where('status', 'approved')->count(),            'paid' => $payrolls->where('status', 'paid')->count(),            'pending' => $payrolls->where('status', 'pending')->count(),        ];    }    public function getEmployeePayrollHistory(int $employeeId, int $limit = 12): Collection    {        return $this->query()->where('employee_id', $employeeId)->orderBy('payroll_year', 'desc')->orderBy('payroll_month', 'desc')->limit($limit)->get();    }}